<span class="line">      <span class="token keyword">const</span> endOfRow <span class="token operator">=</span> <span class="token punctuation">(</span>maxTileIndex <span class="token operator">+</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token operator">*</span> tileSize<span class="token punctuation">;</span></span>
